import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";

import DeanLayout from "../../layouts/DeanLayout";

import {
  getHodSubmissionById
} from "../../api/deanApi";

import hodQuestions from "../../data/hodQuestions";
function getAnswer(answers, questionNo) {

  const item = answers.find(
    (a) => String(a.questionNo) === String(questionNo)
  );

  return item ? item.answer : null;

}

function isImage(value) {

  if (!value) return false;

  return (
    value.endsWith(".jpg") ||
    value.endsWith(".jpeg") ||
    value.endsWith(".png") ||
    value.endsWith(".webp")
  );

}

function isFile(value) {

  if (!value) return false;

  return (
    value.endsWith(".pdf") ||
    value.endsWith(".doc") ||
    value.endsWith(".docx") ||
    value.endsWith(".xls") ||
    value.endsWith(".xlsx")
  );

}

function DeanHodView() {

  const { id } = useParams();

  const navigate = useNavigate();

  const [submission, setSubmission] =
    useState(null);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadSubmission();

  }, []);

  const loadSubmission = async () => {

    try {

      const res =
        await getHodSubmissionById(id);

      setSubmission(res.data.submission);

    }

    catch (err) {

      console.error(err);

    }

    finally {

      setLoading(false);

    }

  };

  if (loading) {

    return (

      <DeanLayout>

        <div style={{ padding: 40 }}>

          Loading...

        </div>

      </DeanLayout>

    );

  }

  if (!submission) {

    return (

      <DeanLayout>

        <div style={{ padding: 40 }}>

          Submission Not Found

        </div>

      </DeanLayout>

    );

  }

  const questionMap = {};

hodQuestions.forEach((section) => {

  section.questions.forEach((question) => {

    questionMap[String(question.questionNo)] =
      question;

  });

});

  return (

    <DeanLayout>

      <div
        style={{
          padding: "35px",
          maxWidth: "1400px",
          margin: "0 auto"
        }}
      >
                <button
          onClick={() => navigate(-1)}
          style={{
            position: "fixed",
            top: "90px",
            right: "30px",
            background: "#dc2626",
            color: "#fff",
            border: "none",
            padding: "12px 24px",
            borderRadius: "10px",
            cursor: "pointer",
            fontWeight: "600",
            zIndex: 9999
          }}
        >
          ✖ Close
        </button>

        <h1
          style={{
            marginBottom: "30px",
            color: "#1e293b"
          }}
        >
          HOD Submission Details
        </h1>

        <div
          style={{
            background: "#fff",
            borderRadius: "12px",
            padding: "25px",
            marginBottom: "35px",
            boxShadow: "0 2px 8px rgba(0,0,0,.08)"
          }}
        >

          <h2
            style={{
              color: "#2563eb",
              marginBottom: "20px"
            }}
          >
            HOD Information
          </h2>

          <table
            style={{
              width: "100%"
            }}
          >

            <tbody>

              <InfoRow
                title="HOD Name"
                value={submission.submittedByName}
              />

              <InfoRow
                title="Email"
                value={submission.submittedByEmail}
              />

              <InfoRow
                title="School"
                value={submission.school}
              />

              <InfoRow
                title="Department"
                value={submission.department}
              />

              <InfoRow
                title="Quarter"
                value={submission.quarter}
              />

              <tr>

                <td style={infoTitle}>
                  Status
                </td>

                <td style={infoValue}>

                  <span
                    style={{
                      background: "#2563eb",
                      color: "#fff",
                      padding: "6px 14px",
                      borderRadius: "20px",
                      fontWeight: "600"
                    }}
                  >
                    {submission.status}
                  </span>

                </td>

              </tr>

            </tbody>

          </table>

        </div>
                <div
          style={{
            display: "grid",
            gridTemplateColumns:
              "repeat(3,1fr)",
            gap: "25px",
            marginBottom: "40px"
          }}
        >

          <SummaryCard
            title="Total Questions"
            value={submission.totalQuestions}
            color="#2563eb"
          />

          <SummaryCard
            title="Answered"
            value={submission.answeredCount}
            color="#16a34a"
          />

          <SummaryCard
            title="Unanswered"
            value={submission.unansweredCount}
            color="#dc2626"
          />

        </div>

        {/* PART 2 STARTS HERE */}
        <h2
  style={{
    color: "#2563eb",
    marginBottom: "25px"
  }}
>
  HOD Responses
</h2>

{
  hodQuestions.map((section) => (

    <div
      key={section.sectionNo}
      style={{
        marginBottom: "35px"
      }}
    >

      <div
        style={{
          background: "#2563eb",
          color: "#fff",
          padding: "16px 20px",
          borderRadius: "10px",
          fontWeight: "700",
          fontSize: "20px",
          marginBottom: "20px"
        }}
      >

        {section.sectionTitle}

      </div>

      {/* PART 3 */}

    </div>

  ))
}

      </div>

    </DeanLayout>

  );

}
